import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"F08: 產能利用率與資產擴張 - 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6290_良維/20260424/F08_產能利用率與資產擴張.md","filePath":"審計報告庫/財務審計/6290_良維/20260424/F08_產能利用率與資產擴張.md"}'),i={name:"審計報告庫/財務審計/6290_良維/20260424/F08_產能利用率與資產擴張.md"};function s(d,t,o,r,g,x){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="f08-產能利用率與資產擴張-投資研究員審計報告" tabindex="-1">F08: 產能利用率與資產擴張 - 投資研究員審計報告 <a class="header-anchor" href="#f08-產能利用率與資產擴張-投資研究員審計報告" aria-label="Permalink to &quot;F08: 產能利用率與資產擴張 - 投資研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司的產能利用率與固定資產擴張率為何？目前處於重資產擴張期 (Heavy Asset) 還是輕資產化轉型？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至 FY2025 全年最新公開數據，良維目前處於 <strong>「產能擴張尾聲 - 收割期」</strong> 的關鍵轉折階段。FY2023-FY2024 為重資產擴張期 (PPE 成長 +52%/+45%)，FY2025 PPE 首次下降 3.9%，但營收大幅成長 26.3%，顯示新增產能已開始轉化為營收動能。PPE/營收比從 19.9% 降至 15.1%，產能效率大幅改善，泰國廠擴產完成後已進入收割期。判定「業績爆發前夕之佈局期已過，現為高效收割期」。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：A (良)</strong></p><ul><li><strong>營收成長率 / 固定資產成長率 (效率係數)</strong>：FY2024 僅 0.20x (投入期)，FY2025 營收 +26.3% vs PPE -3.9%，效率係數顯著轉正，顯示資產已高效利用</li><li><strong>Capex 趨勢</strong>：FY2022 1.47 億 → FY2023 6.21 億 (高峰) → FY2024 5.45 億 → FY2025 3.15 億 (下降 42%)</li><li><strong>折舊覆蓋率 (Capex/Depreciation)</strong>：FY2022: 0.52x, FY2023: 2.50x, FY2024: 2.90x, FY2025: 1.52x (仍大於 1，仍在擴張)</li><li><strong>毛利率趨勢</strong>：FY2023 23.9% → FY2024 24.9% → FY2025 31.4% (大幅躍升，顯示產品組合優化成功)</li><li><strong>月營收動能</strong>：2024 年月均約 6.67 億 → 2025 年月均 8.46 億 (+27%) → 2026 Q1 月均 8.66 億 (持續強勁)</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-生意火熱度-business-momentum" tabindex="-1">1. 生意火熱度 (Business Momentum) <a class="header-anchor" href="#_1-生意火熱度-business-momentum" aria-label="Permalink to &quot;1. 生意火熱度 (Business Momentum)&quot;">​</a></h3><p><strong>資產擴張與營收成長對照：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">科目</th><th style="text-align:left;">FY2022</th><th style="text-align:left;">FY2023</th><th style="text-align:left;">FY2024</th><th style="text-align:left;">FY2025</th></tr></thead><tbody><tr><td style="text-align:left;">營收 (百萬)</td><td style="text-align:left;">7,788</td><td style="text-align:left;">7,360</td><td style="text-align:left;">8,040</td><td style="text-align:left;">10,159</td></tr><tr><td style="text-align:left;">營收年增率</td><td style="text-align:left;">-</td><td style="text-align:left;">-5.5%</td><td style="text-align:left;">+9.2%</td><td style="text-align:left;">+26.3%</td></tr><tr><td style="text-align:left;">固定資產 (PPE, 百萬)</td><td style="text-align:left;">724</td><td style="text-align:left;">1,101</td><td style="text-align:left;">1,597</td><td style="text-align:left;">1,535*</td></tr><tr><td style="text-align:left;">PPE 年增率</td><td style="text-align:left;">-</td><td style="text-align:left;">+52.0%</td><td style="text-align:left;">+45.1%</td><td style="text-align:left;">-3.9%</td></tr><tr><td style="text-align:left;">Capex (百萬)</td><td style="text-align:left;">147</td><td style="text-align:left;">621</td><td style="text-align:left;">545</td><td style="text-align:left;">315</td></tr><tr><td style="text-align:left;">折舊 (百萬)</td><td style="text-align:left;">281</td><td style="text-align:left;">248</td><td style="text-align:left;">188</td><td style="text-align:left;">207</td></tr><tr><td style="text-align:left;">PPE/營收比</td><td style="text-align:left;">9.3%</td><td style="text-align:left;">15.0%</td><td style="text-align:left;">19.9%</td><td style="text-align:left;">15.1%</td></tr><tr><td style="text-align:left;">毛利率</td><td style="text-align:left;">~22.5%</td><td style="text-align:left;">23.9%</td><td style="text-align:left;">24.9%</td><td style="text-align:left;">31.4%</td></tr></tbody></table><p>*FY2025 PPE 使用 H1 數據</p><p>FY2025 營收 +26.3% 但 PPE 首次下降，為「營業槓桿大幅發揮」的訊號。毛利率從 24.9% 升至 31.4% (+6.5ppt)，反映高毛利的資料中心大電流電源線佔比提升。</p><h3 id="_2-擴產價值-expansion-value" tabindex="-1">2. 擴產價值 (Expansion Value) <a class="header-anchor" href="#_2-擴產價值-expansion-value" aria-label="Permalink to &quot;2. 擴產價值 (Expansion Value)&quot;">​</a></h3><p><strong>資本支出週期分析：</strong></p><ul><li><strong>FY2023-2024 為擴產高峰期</strong>：Capex 合計約 11.66 億，主要投入泰國廠擴建 (3 期) 及設備購置</li><li><strong>FY2025 Capex 降至 3.15 億 (-42% YoY)</strong>：泰國廠 1-2 期已完工投產，3 期仍在進行中</li><li><strong>2025 年 11-12 月營收創歷史新高</strong> (9.58 億/8.64 億)，印證擴產效益已反映</li><li><strong>使用權資產下降趨勢</strong>：從 FY2022 3.02 億降至 FY2025 1.68 億 (租約到期減少)，減輕資產負擔</li></ul><p>泰國廠擴產效益量化：法說會提及泰國廠產能可提升 2-4 倍、佔總產能 30%。FY2025 營收 101.59 億創歷史新高，年增 26.3% 的動能中，泰國廠新產能貢獻度顯著。</p><h3 id="_3-投資安全性-safety-margin" tabindex="-1">3. 投資安全性 (Safety Margin) <a class="header-anchor" href="#_3-投資安全性-safety-margin" aria-label="Permalink to &quot;3. 投資安全性 (Safety Margin)&quot;">​</a></h3><ul><li><strong>負債結構健康</strong>：FY2025 負債比僅 26.5%，長期借款 3.06 億 (約佔總資產 2.7%)，財務結構保守</li><li><strong>折舊壓力可控</strong>：年折舊約 2 億，相對於 101.59 億營收僅佔 2.0%</li><li><strong>產能利用率</strong>：法說會提及泰國廠新產能預計 2025 下半年滿載，整體稼動率處於高檔</li><li><strong>無在建工程膨脹警訊</strong>：未發現大規模在建工程 (CIP) 堆積，不需擔心轉固後折舊大幅增加</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>良維正處於商業模式轉型的關鍵時刻：</p><ol><li><p><strong>從重資產轉向高效運轉</strong>：FY2023-2024 是典型的「播種期」 (Capex 大幅高於折舊)，FY2025 進入「收割期」 (Capex 下降但營收跳升)。PPE/營收比從 19.9% 降至 15.1%，資產利用效率顯著改善。</p></li><li><p><strong>輕資產化轉型確認</strong>：FY2025 PPE 絕對值首次下降 (-3.9%)，但毛利率從 24.9% 躍升至 31.4%，符合「固定資產下降 + 毛利率上升 = 成功輕資產化轉型」的定義。良維透過提升高毛利的資料中心/車用產品佔比，而非擴大硬體投資，來推升獲利。</p></li><li><p><strong>輕資產化背後的真正動能</strong>：良維的競爭壁壘在於全球安規認證 (數千張) 而非大量硬體設備。客戶 (Amazon、Apple、Dell) 最看重的是安規合規性與供應鏈韌性，而非產能規模。這是良維能輕資產化的核心原因。</p></li><li><p><strong>未來展望 FY2026</strong>：2026 Q1 月營收持續強勁 (均 8.66 億)，泰國廠 3 期擴產完成後產能將再增 10%+。若毛利率維持 30%+ 水準，EPS 挑戰 10 元+ 可期。Capex 預計維持 3 億左右水準，折舊穩定在 2 億內，現金流充裕。</p></li></ol><p><strong>判定結論</strong>：成長股之星 (擴產收割期)，已通過重資產風險瓶頸。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: <code>balance_sheet 6290 2022-01-01 2026-04-24</code> (科目：PropertyPlantAndEquipment、Inventories、RightOfUseAsset)</li><li><code>數據採集器查詢</code>: <code>cash_flow 6290 2022-01-01 2026-04-24</code> (科目：取得不動產廠房及設備、折舊費用)</li><li><code>數據採集器查詢</code>: <code>finance 6290 2022-01-01 2026-04-24</code> (科目：營業收入、營業成本、毛利、EPS)</li><li><code>數據採集器查詢</code>: <code>revenue 6290 2022-01-01 2026-04-24</code> (科目：月營收)</li><li><code>富聯網 累計損益表</code>: <code>https://ww2.money-link.com.tw/TWStock/StockBasic.aspx?TWMId=Basic_IIAM4&amp;SymId=6290</code> (項目：FY2025 全年毛利率 31.4%)</li><li><code>TreeLazy 良維年報摘要</code>: <code>https://www.treelazy.com/stock/6290</code> (項目：113 年度致股東報告書，含泰國廠產能規劃)</li><li><code>經濟日報</code>: <code>https://money.udn.com/money/story/11074/9369298</code> (項目：2025 年 EPS 8.73 元、配息 6.2 元)</li></ul>',26)])])}const h=e(i,[["render",s]]);export{f as __pageData,h as default};
